const bridgeOutput = $input.first().json;

if (bridgeOutput.output && bridgeOutput.output.length > 10) {
  return [{ json: { output: bridgeOutput.output, elapsed_s: bridgeOutput.elapsed_s || 0, fallback: false, prompt: '' } }];
}

const prompt = $('Build Diagnostic Prompt + Memory').first().json.prompt || '';
return [{ json: { output: '', elapsed_s: 0, fallback: true, prompt: prompt } }];

// Circuit Breaker v3.1 — dedup por signature (workflow_id + failed_node + error_message[:100])
// 
// Camada 1: 10 alertas / 30 min por signature (storm de mesmo erro)
// Camada 2: 30 alertas / 24h por signature (storm sustido de mesmo erro)
// Camada 3: 100 signatures distintas / 24h por workflow_id (hard cap por workflow ruidoso)
//
// FIX v3.1: garbage collection ANTES da inicialização da signature actual
// (v3 deletava a signature acabada de criar quando era nova/vazia → crash em .length)

const errorData = $('Extract Error Data').item.json;
const staticData = $getWorkflowStaticData('global');

const now = Date.now();
const WINDOW_MS = 30 * 60 * 1000;       // 30 minutos
const DAY_MS = 24 * 60 * 60 * 1000;     // 24 horas

const MAX_PER_SIGNATURE_WINDOW = 10;    // mesmo erro, 30 min
const MAX_PER_SIGNATURE_DAY = 30;       // mesmo erro, 24h
const MAX_DISTINCT_PER_WORKFLOW = 100;  // erros distintos por workflow, 24h

// Construir signature: workflow_id + failed_node + first 100 chars of error_message
const workflowId = errorData.workflow_id || 'unknown';
const failedNode = errorData.failed_node || 'unknown';
const errorMsg = (errorData.error_message || '').slice(0, 100);
const signature = `${workflowId}::${failedNode}::${errorMsg}`;

// Init estrutura raiz
staticData.signatures = staticData.signatures || {};

// Garbage collection ANTES de mexer na signature actual:
// limpar timestamps velhos de TODAS as signatures, e remover as que ficam vazias.
// Isto é seguro porque a signature nova ainda não foi criada/inicializada.
for (const sig of Object.keys(staticData.signatures)) {
  staticData.signatures[sig] = staticData.signatures[sig].filter(
    ts => (now - ts) < DAY_MS
  );
  if (staticData.signatures[sig].length === 0) {
    delete staticData.signatures[sig];
  }
}

// AGORA inicializar a signature actual (após GC, garantido que não é deletada)
staticData.signatures[signature] = staticData.signatures[signature] || [];

const sigTimestamps = staticData.signatures[signature];
const sigDayCount = sigTimestamps.length;
const sigWindowCount = sigTimestamps.filter(ts => (now - ts) < WINDOW_MS).length;

// Contar signatures distintas para ESTE workflow nas últimas 24h
const distinctSigsForWorkflow = Object.keys(staticData.signatures).filter(sig => {
  if (!sig.startsWith(`${workflowId}::`)) return false;
  return staticData.signatures[sig].some(ts => (now - ts) < DAY_MS);
}).length;

// Camada 3: hard cap de signatures distintas por workflow
if (distinctSigsForWorkflow >= MAX_DISTINCT_PER_WORKFLOW) {
  return [{
    json: {
      ...errorData,
      suppress_alerts: true,
      suppress_reason: `WORKFLOW_HARD_CAP: ${distinctSigsForWorkflow}/${MAX_DISTINCT_PER_WORKFLOW} distinct errors in 24h for workflow ${workflowId}`,
      suppress_count: distinctSigsForWorkflow,
      kill_switch: true,
      signature: signature
    }
  }];
}

// Camada 2: storm sustido de mesmo erro (24h)
if (sigDayCount >= MAX_PER_SIGNATURE_DAY) {
  return [{
    json: {
      ...errorData,
      suppress_alerts: true,
      suppress_reason: `SIGNATURE_DAILY: ${sigDayCount}/${MAX_PER_SIGNATURE_DAY} same-error alerts in 24h for ${signature.slice(0, 80)}`,
      suppress_count: sigDayCount,
      kill_switch: false,
      signature: signature
    }
  }];
}

// Camada 1: storm curto de mesmo erro (30 min)
if (sigWindowCount >= MAX_PER_SIGNATURE_WINDOW) {
  return [{
    json: {
      ...errorData,
      suppress_alerts: true,
      suppress_reason: `SIGNATURE_RATE_LIMIT: ${sigWindowCount}/${MAX_PER_SIGNATURE_WINDOW} same-error alerts in ${WINDOW_MS/60000}min for ${signature.slice(0, 80)}`,
      suppress_count: sigWindowCount,
      kill_switch: false,
      signature: signature
    }
  }];
}

// Permitir alerta + registar timestamp
staticData.signatures[signature].push(now);

return [{
  json: {
    ...errorData,
    suppress_alerts: false,
    suppress_count: staticData.signatures[signature].length,
    distinct_count: distinctSigsForWorkflow + 1,
    signature: signature
  }
}];

const response = $input.first().json;
const text = response.content && response.content[0] ? response.content[0].text : JSON.stringify(response);
return [{ json: { output: text + '\n\n⚠️ Gerado via Haiku API (fallback — Claude Bridge indisponivel)', elapsed_s: 0 } }];

